#include<bits/stdc++.h>
using namespace std;
int mp[305][305],f[305][305],pre[305][305];
vector<int> res;
void print(int l,int r)
{
    if(pre[l][r]==0)
    {
        return;
    }
    print(l,pre[l][r]);
    res.push_back(pre[l][r]);
    print(pre[l][r],r);
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    memset(mp,0x3f,sizeof(mp));
    memset(f,0x3f,sizeof(f));
    for(int i=1;i<=m;i++)
    {
        int x,y,z;
        scanf("%d%d%d",&x,&y,&z);
        mp[x][y]=mp[y][x]=f[x][y]=f[y][x]=min(mp[x][y],z);
    }
    for(int i=1;i<=n;i++)
    {
        f[i][i]=mp[i][i]=0;
    }
    int ans=0x3f3f3f3f;
    for(int k=1;k<=n;k++)
    {
        for(int i=1;i<k;i++)
        {
            for(int j=i+1;j<k;j++)
            {
                if((long long)f[i][j]+mp[j][k]+mp[k][i]<ans)
                {
                    ans=f[i][j]+mp[j][k]+mp[k][i];
                    res.clear();
                    print(i,j);
                    res.push_back(j);
                    res.push_back(k);
                    res.push_back(i);
                }
            }
        }
        for(int i=1;i<=n;i++)if(i!=k)
        {
            for(int j=1;j<=n;j++)if(i!=j&&k!=j)
            {
                if(f[i][k]+f[k][j]<f[i][j])
                {
                    f[i][j]=f[i][k]+f[k][j];
                    pre[i][j]=k;
                }
            }
        }
    }
    if(ans==0x3f3f3f3f)
    {
        printf("No solution.");
        return 0;
    }
    int flag=1;
    for(int i:res)
    {
        if(flag==0)
        {
            printf(" ");
        }
        flag=0;
        printf("%d",i);
    }
    return 0;
}
